{
  "grammar": [
    {
      "pattern": "Subject + 應該 + Verb + Object",
      "structure": ["Subject", "應該", "Verb", "Object"],
      "explanation_en": "Use '應該' to express that something should be done based on reason, expectation, or social norm. It is softer than '必須' and often used for advice.",
      "title": "應該 for Should",
      "meaning": "Should / ought to",
      "when_to_use": ["Giving advice or suggestions", "Expressing what is expected or appropriate", "Talking about obligations that are not strict"],
      "when_not_to_use": ["For strong obligations or rules (use 必須)", "For personal desires (use 想)"],
      "pragmatic_notes": "In Taiwan, '應該' is common in polite advice. It can also mean 'probably' when used with uncertainty, e.g., '他應該會來'.",
      "word_order_notes": "Place '應該' before the main verb, after the subject. Negation: '不應該' (should not).",
      "english_contrast": "English uses 'should' similarly, but Chinese does not have a separate modal for 'ought to'.",
      "korean_contrast": "Korean uses '-아/어야 하다' for obligation, but '應該' is closer to '-는 것이 좋다' (it is good to).",
      "negative_examples": [
        {
          "text": "我應該不喝咖啡。",
          "error": "Negation should be '不應該' before the verb, not after '應該'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他應該去學校嗎？",
          "error": "This is correct. No error here."
        }
      ],
      "transformation_drills": ["Change '你應該吃藥' to negative.", "Change '我們應該早點到' to a question."],
      "production_drills": ["Give advice to a friend who is tired.", "Say what you should do before an exam."],
      "common_error_patterns": ["Placing '不' after '應該' instead of before", "Using '應該' for strong rules"],
      "repair_feedback": {
        "word_order": "Put '不' before '應該' for negation.",
        "politeness": "Use '應該' for polite advice, not commands.",
        "vocabulary": "Use '必須' for strong obligations."
      }
    },
    {
      "pattern": "Subject + 需要 + Verb + Object",
      "structure": ["Subject", "需要", "Verb", "Object"],
      "explanation_en": "Use '需要' to express that something is needed or necessary. It can also mean 'need to' as a verb. It is less strong than '必須' but more concrete than '應該'.",
      "title": "需要 for Need",
      "meaning": "Need to / must (less strong)",
      "when_to_use": ["Expressing necessity based on situation", "Talking about requirements", "Asking if something is needed"],
      "when_not_to_use": ["For moral obligation (use 應該)", "For strict rules (use 必須)"],
      "pragmatic_notes": "In Taiwan, '需要' is common in service contexts, e.g., '你需要袋子嗎？' It can also be a noun meaning 'need'.",
      "word_order_notes": "Place '需要' before the main verb. Negation: '不需要' (don't need to).",
      "english_contrast": "English 'need to' is similar, but Chinese '需要' can also be used as a main verb (我需要水).",
      "korean_contrast": "Korean uses '필요하다' for need, but '需要' is more like '-아/어야 하다' in necessity.",
      "negative_examples": [
        {
          "text": "我需要不喝水。",
          "error": "Negation should be '不需要' before the verb, not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他需要去醫院嗎？",
          "error": "This is correct. No error here."
        }
      ],
      "transformation_drills": ["Change '我需要買水' to negative.", "Change '你需要休息' to a question."],
      "production_drills": ["Ask a friend if they need help.", "Say what you need to do today."],
      "common_error_patterns": ["Using '需要' for moral advice", "Negation placement error"],
      "repair_feedback": {
        "word_order": "Put '不' before '需要' for negation.",
        "politeness": "Use '需要' for practical needs, not for suggestions.",
        "vocabulary": "Use '應該' for advice, '必須' for rules."
      }
    },
    {
      "pattern": "Subject + 必須 + Verb + Object",
      "structure": ["Subject", "必須", "Verb", "Object"],
      "explanation_en": "Use '必須' to express a strong obligation or necessity, often due to rules, laws, or unavoidable circumstances. It is stronger than '應該' and '需要'.",
      "title": "必須 for Must",
      "meaning": "Must / have to",
      "when_to_use": ["Expressing strong obligations", "Talking about rules or requirements", "Emphasizing necessity"],
      "when_not_to_use": ["For polite advice (use 應該)", "For personal needs (use 需要)"],
      "pragmatic_notes": "In Taiwan, '必須' is used in formal contexts like signs, rules, or serious advice. It can sound too strong in casual conversation.",
      "word_order_notes": "Place '必須' before the main verb. Negation: '不必' or '不用' (don't have to), not '不必須'.",
      "english_contrast": "English 'must' is similar, but Chinese '必須' is less common in spoken advice; '應該' is more polite.",
      "korean_contrast": "Korean uses '-아/어야 한다' for must, similar to '必須', but '必須' is more formal.",
      "negative_examples": [
        {
          "text": "我不必須去。",
          "error": "Negation of '必須' is '不必' or '不用', not '不必須'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你必須吃藥。",
          "error": "This is correct if it's a strong necessity. No error here."
        }
      ],
      "transformation_drills": ["Change '你必須早點到' to negative using '不必'.", "Change '我們必須遵守規定' to a question."],
      "production_drills": ["Tell a friend they must wear a mask in the hospital.", "Say what you must do before leaving."],
      "common_error_patterns": ["Using '不必須' instead of '不必'", "Using '必須' for polite advice"],
      "repair_feedback": {
        "word_order": "Use '不必' for negation, not '不必須'.",
        "politeness": "Use '應該' for polite advice, '必須' for strong rules.",
        "vocabulary": "Use '需要' for personal needs."
      }
    }
  ]
}
